"use client";

import * as React from "react";
import {
  type MotionValue,
  type SpringOptions,
  useSpring,
} from "motion/react";

import {
  HorizontalTrack,
  type HorizontalTrackMetrics,
  type HorizontalTrackProps,
} from "@/components/experience/horizontal-track";
import { cn } from "@/lib/utils";
import { useCoarsePointer, useExperienceViewport, usePrefersReducedMotion } from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type HorizontalStoryRailProps = Omit<React.ComponentProps<"section">, "children"> & {
  children: React.ReactNode;
  label: string;
  itemClassName?: HorizontalTrackProps["itemClassName"];
  stageClassName?: string;
  trackClassName?: string;
  progressClassName?: HorizontalTrackProps["progressClassName"];
  progressIndicatorClassName?: HorizontalTrackProps["progressIndicatorClassName"];
  showProgress?: boolean;
  progress?: MotionValue<number>;
  renderCounter?: HorizontalTrackProps["renderCounter"];
  scrollSpring?: false | SpringOptions;
};

const DEFAULT_SCROLL_SPRING: SpringOptions = {
  stiffness: 120,
  damping: 28,
  mass: 0.22,
};

/**
 * A pinned scene where native vertical page scroll drives a horizontal track.
 * Reduced-motion users receive the same content as a normal vertical list.
 */
export function HorizontalStoryRail({
  children,
  className,
  itemClassName,
  label,
  progress: controlledProgress,
  progressClassName,
  progressIndicatorClassName,
  renderCounter,
  scrollSpring = false,
  showProgress = true,
  stageClassName,
  style,
  trackClassName,
  ...props
}: HorizontalStoryRailProps) {
  const sectionRef = React.useRef<HTMLElement>(null);
  const items = React.Children.toArray(children);
  const [metrics, setMetrics] = React.useState({ distance: 0, viewportHeight: 0 });
  const prefersReducedMotion = usePrefersReducedMotion();
  const coarsePointer = useCoarsePointer();
  const viewport = useExperienceViewport();

  const scrollYProgress = useElementScrollProgress(sectionRef);
  const smoothedProgress = useSpring(scrollYProgress, scrollSpring || DEFAULT_SCROLL_SPRING);
  const progress = controlledProgress ?? (scrollSpring === false ? scrollYProgress : smoothedProgress);
  const handleMetricsChange = React.useCallback((next: HorizontalTrackMetrics) => {
    setMetrics({ distance: next.distance, viewportHeight: next.viewportHeight });
  }, []);

  if (prefersReducedMotion) {
    return (
      <section
        ref={sectionRef}
        aria-label={label}
        data-horizontal-story="reduced"
        data-experience-viewport={viewport}
        className={cn("relative", className)}
        style={style}
        {...props}
      >
        <div role="list" className={cn("grid gap-4 py-8", trackClassName)}>
          {items.map((child, index) => {
            const counter = renderCounter?.(index + 1, items.length) ?? `${index + 1} / ${items.length}`;
            const counterLabel = typeof counter === "string" || typeof counter === "number"
              ? String(counter)
              : undefined;
            return (
              <div
                key={React.isValidElement(child) && child.key != null ? child.key : index}
                role="listitem"
                aria-label={counterLabel}
                className={typeof itemClassName === "function" ? itemClassName(index) : itemClassName}
              >
                {counterLabel === undefined ? <span className="sr-only">{counter}</span> : null}
                {child}
              </div>
            );
          })}
        </div>
      </section>
    );
  }

  if (coarsePointer || viewport !== "desktop") {
    return (
      <section ref={sectionRef} aria-label={label} data-horizontal-story="native-snap" data-experience-viewport={viewport} className={cn("relative min-w-0 overflow-hidden", className)} style={style} {...props}>
        <div role="list" className={cn("flex snap-x snap-mandatory gap-4 overflow-x-auto px-5 py-12 [scrollbar-width:none] sm:gap-6 sm:px-8 sm:py-16 [&::-webkit-scrollbar]:hidden", trackClassName)}>
          {items.map((child, index) => {
            const counter = renderCounter?.(index + 1, items.length) ?? `${index + 1} / ${items.length}`;
            const counterLabel = typeof counter === "string" || typeof counter === "number" ? String(counter) : undefined;
            return <div key={React.isValidElement(child) && child.key != null ? child.key : index} role="listitem" aria-label={counterLabel} className={cn("w-[86vw] shrink-0 snap-center sm:w-[min(68vw,38rem)]", typeof itemClassName === "function" ? itemClassName(index) : itemClassName)}>{counterLabel === undefined ? <span className="sr-only">{counter}</span> : null}{child}</div>;
          })}
        </div>
      </section>
    );
  }

  const scrollHeight = Math.max(
    metrics.viewportHeight * 2,
    metrics.viewportHeight + metrics.distance,
  );

  return (
    <section
      ref={sectionRef}
      aria-label={label}
      data-horizontal-story="vertical-driven"
      data-experience-viewport={viewport}
      className={cn("relative", className)}
      style={{ minHeight: `${Math.max(items.length, 2) * 85}svh`, height: scrollHeight, ...style }}
      {...props}
    >
      <div className={cn("sticky top-0 h-svh overflow-hidden", stageClassName)}>
        <HorizontalTrack
          label={label}
          progress={progress}
          itemClassName={itemClassName}
          renderCounter={renderCounter}
          trackClassName={trackClassName}
          showProgress={showProgress}
          progressClassName={progressClassName}
          progressIndicatorClassName={progressIndicatorClassName}
          onMetricsChange={handleMetricsChange}
        >
          {items}
        </HorizontalTrack>
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import { motion, type MotionValue, useTransform } from "motion/react";

import { cn } from "@/lib/utils";
import { clamp01, useExperienceViewport } from "@/components/experience/experience-runtime";

export type HorizontalTrackMetrics = {
  distance: number;
  trackWidth: number;
  viewportHeight: number;
  viewportWidth: number;
};

export type HorizontalTrackProps = Omit<React.ComponentProps<"div">, "children"> & {
  children: React.ReactNode;
  itemClassName?: string | ((index: number) => string | undefined);
  label: string;
  onMetricsChange?: (metrics: HorizontalTrackMetrics) => void;
  progress: MotionValue<number>;
  progressClassName?: string;
  progressIndicatorClassName?: string;
  /** Custom item counter, e.g. `(current, total) => \`${current} of ${total}\``. Defaults to "2 / 5". */
  renderCounter?: (current: number, total: number) => React.ReactNode;
  showProgress?: boolean;
  trackClassName?: string;
};

function sameMetrics(left: HorizontalTrackMetrics, right: HorizontalTrackMetrics) {
  return left.distance === right.distance
    && left.trackWidth === right.trackWidth
    && left.viewportHeight === right.viewportHeight
    && left.viewportWidth === right.viewportWidth;
}

/**
 * A measured horizontal track controlled by an external normalized progress.
 * It owns no sticky section or scroll listener, so it can live inside another
 * timeline, a 2.5D stage, a carousel controller, or a standalone composition.
 */
export function HorizontalTrack({
  children,
  className,
  itemClassName,
  label,
  onMetricsChange,
  progress,
  progressClassName,
  progressIndicatorClassName,
  renderCounter,
  showProgress = true,
  style,
  trackClassName,
  ...props
}: HorizontalTrackProps) {
  const viewport = useExperienceViewport();
  const viewportRef = React.useRef<HTMLDivElement>(null);
  const trackRef = React.useRef<HTMLDivElement>(null);
  const metricsRef = React.useRef<HorizontalTrackMetrics>({
    distance: 0,
    trackWidth: 0,
    viewportHeight: 0,
    viewportWidth: 0,
  });
  const items = React.Children.toArray(children);
  const [distance, setDistance] = React.useState(0);
  const x = useTransform(progress, [0, 1], [0, -distance], { clamp: true });
  const progressScale = useTransform(progress, (value) => clamp01(value));

  React.useEffect(() => {
    const viewport = viewportRef.current;
    const track = trackRef.current;
    if (!viewport || !track) return;

    const measure = () => {
      const next: HorizontalTrackMetrics = {
        distance: Math.max(0, track.scrollWidth - viewport.clientWidth),
        trackWidth: track.scrollWidth,
        viewportHeight: viewport.clientHeight,
        viewportWidth: viewport.clientWidth,
      };
      if (sameMetrics(metricsRef.current, next)) return;
      metricsRef.current = next;
      setDistance(next.distance);
      onMetricsChange?.(next);
    };

    const observer = new ResizeObserver(measure);
    observer.observe(viewport);
    observer.observe(track);
    measure();
    return () => observer.disconnect();
  }, [items.length, onMetricsChange]);

  return (
    <div
      ref={viewportRef}
      data-horizontal-track-viewport
      data-experience-viewport={viewport}
      className={cn("relative flex h-full w-full min-w-0 items-center overflow-hidden", className)}
      style={style}
      {...props}
    >
      <motion.div
        ref={trackRef}
        role="list"
        aria-label={label}
        data-horizontal-track
        className={cn(
          "flex w-max items-stretch gap-4 px-5 will-change-transform sm:gap-6 sm:px-8 lg:gap-[clamp(1rem,2.5vw,2.5rem)] lg:px-[max(1.25rem,5vw)]",
          trackClassName,
        )}
        style={{ x }}
      >
        {items.map((child, index) => {
          const key = React.isValidElement(child) && child.key != null ? child.key : index;
          const resolvedItemClassName = typeof itemClassName === "function"
            ? itemClassName(index)
            : itemClassName;
          const counter = renderCounter?.(index + 1, items.length) ?? `${index + 1} / ${items.length}`;
          const counterLabel = typeof counter === "string" || typeof counter === "number"
            ? String(counter)
            : undefined;

          return (
            <div
              key={key}
              role="listitem"
              aria-label={counterLabel}
              data-horizontal-track-item={index}
              className={cn("w-[86vw] shrink-0 sm:w-[min(68vw,42rem)] lg:w-[min(82vw,62rem)]", resolvedItemClassName)}
            >
              {counterLabel === undefined ? <span className="sr-only">{counter}</span> : null}
              {child}
            </div>
          );
        })}
      </motion.div>

      {showProgress ? (
        <div
          aria-hidden
          className={cn(
            "absolute inset-x-5 bottom-4 h-px origin-left bg-current/20 sm:inset-x-8 sm:bottom-6 lg:inset-x-[max(1.25rem,5vw)]",
            progressClassName,
          )}
        >
          <motion.div
            className={cn("h-full origin-left bg-current", progressIndicatorClassName)}
            style={{ scaleX: progressScale }}
          />
        </div>
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
  mode: "pinned" | "entry" = "pinned",
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const value = mode === "entry"
        ? (window.innerHeight - rect.top) / Math.max(1, element.offsetHeight)
        : -rect.top / Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, value)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [mode, progress, target]);

  return progress;
}

# HorizontalTrack

Motor orizontal măsurat, controlat exclusiv printr-un `MotionValue<number>` extern. Componenta nu creează o secțiune sticky, nu citește scroll-ul global și nu impune un timeline. Poate fi montată într-o scenă 2.5D, într-un controller de carousel sau într-un alt recipe.

## Instalare

```bash
npx shadcn@latest add ./public/r/horizontal-track.json
```

## Exemplu controlat

```tsx
import { useTransform } from "motion/react"

import { HorizontalTrack } from "@/components/experience/horizontal-track"

const catalogProgress = useTransform(sceneProgress, [0.75, 0.96], [0, 1], {
  clamp: true,
})

<HorizontalTrack
  label="Catalog"
  progress={catalogProgress}
  itemClassName={(index) => index === 1 ? "w-[56vw]" : "w-[34vw]"}
  trackClassName="gap-4 px-[8vw]"
>
  {items.map((item) => <CatalogCard key={item.id} item={item} />)}
</HorizontalTrack>
```

`progress` este normalizat la `0…1`. Componenta măsoară `track.scrollWidth - viewport.clientWidth`, observă track-ul și viewport-ul cu `ResizeObserver` și recalculează automat după resize, font loading sau schimbarea dimensiunilor conținutului.

## Contract

- `HorizontalTrack` este o infrastructură controlată, nu o mecanică signature pe care Studio o propune singură clientului;
- parent-ul decide sursa progresului, sticky behavior-ul, timeline-ul și fallback-ul reduced-motion;
- `itemClassName` acceptă o clasă comună sau o funcție per index, deci item-urile pot avea lățimi diferite;
- `trackClassName` personalizează gap-ul, padding-ul și alinierea;
- `onMetricsChange` expune distanța, dimensiunea track-ului și viewport-ul pentru controllere externe;
- conținutul rămâne React semantic, iar ordinea DOM nu se schimbă.

Pentru varianta vertical-scroll completă folosește `HorizontalStoryRail`. Pentru catalogul final al unei scene cinematice, compune `HorizontalTrack` cu un controller de index/drag și animă intrarea întregului catalog prin timeline-ul scenei.

## QA

- testează `progress` la `0`, `0.5` și `1`;
- modifică lățimea viewport-ului după montare;
- verifică item-uri cu lățimi diferite și conținut încărcat lent;
- verifică faptul că primul și ultimul item se așază complet;
- parent-ul trebuie să ofere fallback normal pentru touch și `prefers-reduced-motion`;
- nu transforma acest building block într-un carousel fără controale, drag/swipe și tastatură.

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
